import JSZip from 'jszip';
import { serviceMeta } from './AdditionalServicesStep';
import { mediaServerMeta } from './mediaServerMeta';

/**
 * deployBundle.js — generates a downloadable deploy bundle from the
 * user's wizard config + the schema. The bundle is everything the
 * orchestrator needs to deploy a real Surge stack on the target host.
 *
 * Bundle layout:
 *   surge-deploy/
 *     manifest.json              — schema export (serviceMeta + mediaServerMeta)
 *     config.json                — user's wizard config
 *     state.json (optional)      — preserved from a prior deploy if uploaded
 *     scripts/                   — every configure-/fetch-*.py
 *     orchestrator/              — surge_orchestrator.py
 *     run.sh                     — one-liner that invokes the orchestrator
 *     README.md                  — platform-specific deploy instructions
 *
 * Generation flow:
 *   1. Strip MUI logo imports from the schema (they'd serialize as
 *      webpack-resolved filenames, useless in the bundle).
 *   2. Fetch every script + orchestrator file from /deploy_assets/
 *      (populated by frontend/scripts/copy-deploy-assets.js as a
 *      prebuild step).
 *   3. Generate README.md with platform-specific quickstart text.
 *   4. Generate run.sh with the right paths.
 *   5. ZIP it up via JSZip and return the Blob.
 */

// ---------------------------------------------------------------------
// Schema export
// ---------------------------------------------------------------------

function stripLogos(meta) {
  // Logos are webpack-resolved imports — serialize as bare filename
  // strings, useless to the orchestrator. Strip them so the manifest
  // is data-only.
  const out = {};
  for (const [k, v] of Object.entries(meta)) {
    const { logo, ...rest } = v;
    out[k] = rest;
  }
  return out;
}

export function buildManifest() {
  return {
    serviceMeta:     stripLogos(serviceMeta),
    mediaServerMeta: stripLogos(mediaServerMeta),
  };
}

// ---------------------------------------------------------------------
// Asset fetching
// ---------------------------------------------------------------------

async function fetchAsset(relativePath) {
  // /deploy_assets/ is served from frontend/public/deploy_assets/, which
  // copy-deploy-assets.js populates from ../scripts/ + ../orchestrator/.
  const res = await fetch(`/deploy_assets/${relativePath}`);
  if (!res.ok) {
    throw new Error(
      `Failed to fetch /deploy_assets/${relativePath}: HTTP ${res.status}`,
    );
  }
  return res.text();
}

async function fetchInventory() {
  const res = await fetch('/deploy_assets/inventory.json');
  if (!res.ok) {
    throw new Error(
      `Failed to fetch /deploy_assets/inventory.json: HTTP ${res.status}. ` +
      `The prebuild hook may not have run — check frontend/scripts/` +
      `copy-deploy-assets.js or run \`npm run copy-deploy-assets\`.`,
    );
  }
  return res.json();
}

// ---------------------------------------------------------------------
// Generated files (README + run.sh)
// ---------------------------------------------------------------------

function generateReadme({ platform, mediaServer, enabledServices }) {
  const isUnraid = platform === 'unraid';
  const stack = enabledServices.join(', ') || '(none)';

  // Header + summary section common to both platforms.
  const header = [
    '# Surge deploy bundle',
    '',
    'This bundle was generated by the Surge wizard and contains everything',
    'needed to deploy your selected stack on the target host:',
    '',
    `- Media server: **${mediaServer || '(none)'}**`,
    `- Additional services: ${stack}`,
    `- Target platform: **${platform}**`,
    '',
    '## What\'s in the bundle',
    '',
    '```',
    'manifest.json              Schema export (serviceMeta + mediaServerMeta)',
    'config.json                Your wizard config (replace before re-deploying)',
    'state.json (optional)      Generated secrets — preserved from prior deploys',
    'orchestrator/              Python orchestrator (stdlib-only, runs on the target)',
    'scripts/                   configure-*.py / fetch-*.py for cross-service wiring',
    'run.sh                     One-line wrapper that invokes the orchestrator',
    '```',
    '',
    '## Requirements on the target host',
    '',
    '- Python 3.10 or newer',
    '- Docker + Docker Compose (`docker compose` v2 plugin)',
    '- Free ports for the services in your stack — if anything is already',
    '  bound, edit `config.json` before deploying.',
    '',
  ];

  const unraidQuickstart = [
    '## Unraid quickstart',
    '',
    '1. Copy this entire `surge-deploy/` folder to your Unraid server, e.g.:',
    '   ```',
    '   scp -r surge-deploy root@unraid:/mnt/user/appdata/surge/',
    '   ```',
    '',
    '2. SSH in and run the deploy:',
    '   ```',
    '   ssh root@unraid',
    '   cd /mnt/user/appdata/surge',
    '   ./run.sh',
    '   ```',
    '',
    '   Or use the **User Scripts** plugin: Settings → User Scripts → Add → paste:',
    '   ```bash',
    '   #!/bin/bash',
    '   cd /mnt/user/appdata/surge && ./run.sh',
    '   ```',
    '',
    '3. (Optional) For Unraid UI integration: install the **Compose Manager**',
    '   plugin from Community Apps. Compose Manager will pick up the',
    '   `docker-compose.yaml` the orchestrator generates at',
    '   `/mnt/user/appdata/surge/surge-deploy/compose.yaml` and give you',
    '   start/stop/log buttons in the Unraid UI.',
    '',
    '## Re-deploying',
    '',
    'When you change your wizard config and download a new bundle, **upload',
    'the prior `state.json` into the wizard\'s Deploy step BEFORE downloading**.',
    'The new bundle will then carry forward your generated secrets (so already-',
    'running services don\'t break) and only update what changed.',
    '',
  ];

  const dockerQuickstart = [
    '## Docker host quickstart',
    '',
    '1. Extract the bundle and `cd surge-deploy/`.',
    '2. Run:',
    '   ```',
    '   ./run.sh',
    '   ```',
    '',
    '   The orchestrator will:',
    '   - Generate any missing secrets (random hex), persist to `state.json`',
    '   - Resolve all cross-service references in the schema',
    '   - Write `compose.yaml` and any seeded config files (e.g. `sonarr/config.xml`)',
    '   - Run `docker compose up -d` to bring everything up',
    '   - Run fetchScripts (capture runtime values like Plex token)',
    '   - Run postDeployScripts (configure download clients, register apps,',
    '     create Plex libraries, etc.)',
    '',
    '## Re-deploying',
    '',
    'Re-running `./run.sh` is safe and idempotent — secrets are reused from',
    '`state.json`, configure scripts skip already-configured items.',
    '',
    'To preserve secrets across config changes from the wizard, upload your',
    '`state.json` into the wizard\'s Deploy step before downloading a new',
    'bundle. The new bundle will keep the same secret values.',
    '',
  ];

  const footer = [
    '## Pinning image versions (production stability)',
    '',
    'All services in the generated `compose.yaml` use `:latest` tags. That',
    'matches most users\' expectations (auto-pull updates) but means a',
    'breaking upstream release can knock out your stack overnight. To pin',
    'specific versions:',
    '',
    '1. Run the orchestrator once so `compose-out/compose.yaml` exists.',
    '2. Edit it directly: replace each `image: foo/bar:latest` with the',
    '   pinned tag or digest you want, e.g.',
    '   `image: foo/bar:1.2.3` or `image: foo/bar@sha256:abc...`.',
    '3. Run `docker compose -f compose-out/compose.yaml up -d` to apply.',
    '',
    'Re-running the orchestrator (`./run.sh`) will regenerate compose.yaml',
    'from scratch and **lose your pinned tags**. To preserve them across',
    'orchestrator re-runs, copy `compose.yaml` to `compose.pinned.yaml`',
    'and use that with `docker compose -f compose.pinned.yaml ...` for all',
    'subsequent up/down/pull operations. The orchestrator\'s scripts run',
    'against the live service ports regardless of which compose file you',
    'used to start them.',
    '',
    'Useful tag references:',
    '- linuxserver/* services (Sonarr/Radarr/Bazarr/etc.): https://fleet.linuxserver.io',
    '- Plex: `plexinc/pms-docker:public` for stable, `:plexpass` for beta',
    '- Jellyfin: https://hub.docker.com/r/jellyfin/jellyfin/tags',
    '',
    '## Scheduling re-deploys (image updates)',
    '',
    'To pull the latest image versions and restart your stack on a',
    'schedule, point cron or a systemd timer at the orchestrator with',
    'a small wrapper. The orchestrator is idempotent so re-runs are',
    'safe — secrets are reused from `state.json`, configure scripts',
    'skip already-configured items.',
    '',
    'Cron (weekly Sunday 4am):',
    '```',
    '0 4 * * 0  cd /path/to/surge-deploy && \\',
    '    docker compose -f compose-out/compose.yaml pull && \\',
    '    ./run.sh >> .surge/cron.log 2>&1',
    '```',
    '',
    'Systemd timer (preferred on modern hosts):',
    '```',
    '# /etc/systemd/system/surge-update.service',
    '[Unit]',
    'Description=Surge stack update',
    '',
    '[Service]',
    'Type=oneshot',
    'WorkingDirectory=/path/to/surge-deploy',
    'ExecStart=/bin/bash -c "docker compose -f compose-out/compose.yaml pull && ./run.sh"',
    '',
    '# /etc/systemd/system/surge-update.timer',
    '[Unit]',
    'Description=Run Surge update weekly',
    '',
    '[Timer]',
    'OnCalendar=weekly',
    'Persistent=true',
    '',
    '[Install]',
    'WantedBy=timers.target',
    '```',
    '',
    'Enable with `sudo systemctl enable --now surge-update.timer`.',
    '',
    'On Unraid, the **User Scripts** plugin can do the same job — set',
    'the schedule to "Custom" with cron expression `0 4 * * 0` and use',
    'the same wrapper script as above.',
    '',
    '## Manual orchestrator invocation',
    '',
    'If you need to inspect or override the orchestrator\'s defaults:',
    '',
    '```',
    'python3 orchestrator/surge_orchestrator.py \\',
    '    --manifest manifest.json \\',
    '    --config config.json \\',
    '    --state-dir .surge \\',
    '    --output-dir compose-out \\',
    '    --scripts-dir scripts \\',
    '    --dry-run    # Preview without mutating',
    '```',
    '',
    'Useful flags:',
    '  --dry-run         Resolve everything, log what would happen, exit',
    '  --skip-up         Generate compose.yaml + seeded files; skip docker up',
    '  --skip-scripts    docker up everything; skip configure/fetch scripts',
    '  --verbose         Extra log detail',
    '',
    '## Troubleshooting',
    '',
    '- **Permission errors writing to `/mnt/user/...`**: the orchestrator runs',
    '  as the user that invokes it. On Unraid, run as root via SSH or User Scripts.',
    '- **Plex won\'t start**: check that `PLEX_CLAIM` in `config.json` is current —',
    '  Plex claim tokens expire after ~4 minutes. Get a fresh one from',
    '  https://www.plex.tv/claim and re-run.',
    '- **`docker compose up` fails**: read `compose.yaml` directly to see the',
    '  resolved config, then run `docker compose up -d <single-service>` to isolate.',
    '- **A configure script fails**: each script is idempotent; re-running the',
    '  orchestrator picks up where it left off. Logs land at stderr.',
    '',
  ];

  return [
    ...header,
    ...(isUnraid ? unraidQuickstart : dockerQuickstart),
    ...footer,
  ].join('\n');
}

function generateRunSh() {
  return [
    '#!/usr/bin/env bash',
    '# Generated by Surge wizard. Runs the orchestrator with the bundle\'s',
    '# manifest + config. Re-run safely — orchestrator is idempotent.',
    '',
    'set -euo pipefail',
    '',
    'SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"',
    'cd "$SCRIPT_DIR"',
    '',
    'exec python3 orchestrator/surge_orchestrator.py \\',
    '    --manifest    manifest.json \\',
    '    --config      config.json \\',
    '    --state-dir   .surge \\',
    '    --output-dir  compose-out \\',
    '    --scripts-dir scripts \\',
    '    "$@"',
    '',
  ].join('\n');
}

// ---------------------------------------------------------------------
// Bundle assembly
// ---------------------------------------------------------------------

/**
 * Build a deploy bundle ZIP from the wizard config.
 *
 * @param {object} args
 * @param {object} args.config       - User's wizard config (will be JSON-stringified into bundle)
 * @param {object} [args.priorState] - Optional state.json from a prior deploy (preserves secrets)
 * @returns {Promise<Blob>}            ZIP Blob ready for download
 */
export async function buildDeployBundle({ config, priorState = null }) {
  const inventory = await fetchInventory();
  const manifest  = buildManifest();

  // Summarize what's in the deploy for the README header.
  const enabledServices = Object.entries(config.contentEnhancement || {})
    .filter(([, enabled]) => enabled)
    .map(([key]) => key)
    .sort();
  const platform = config.platform || 'docker';

  const readme = generateReadme({
    platform,
    mediaServer: config.mediaServer,
    enabledServices,
  });
  const runSh = generateRunSh();

  const zip = new JSZip();
  const root = zip.folder('surge-deploy');

  // Top-level files.
  root.file('manifest.json', JSON.stringify(manifest, null, 2));
  root.file('config.json',   JSON.stringify(config, null, 2));
  if (priorState) {
    // Save under .surge/ so the orchestrator picks it up by default.
    root.folder('.surge').file('state.json', JSON.stringify(priorState, null, 2));
  }
  root.file('README.md', readme);
  // run.sh marked executable in the ZIP — JSZip's unixPermissions field
  // preserves the bit on extraction.
  root.file('run.sh', runSh, { unixPermissions: 0o755 });

  // Scripts directory.
  const scriptsFolder = root.folder('scripts');
  await Promise.all(
    inventory.scripts.map(async (rel) => {
      const content = await fetchAsset(rel);
      const name = rel.split('/').pop();
      scriptsFolder.file(name, content, { unixPermissions: 0o755 });
    }),
  );

  // Orchestrator directory.
  const orchFolder = root.folder('orchestrator');
  await Promise.all(
    inventory.orchestrator.map(async (rel) => {
      const content = await fetchAsset(rel);
      const name = rel.split('/').pop();
      orchFolder.file(name, content, { unixPermissions: 0o755 });
    }),
  );

  return zip.generateAsync({
    type:               'blob',
    compression:        'DEFLATE',
    compressionOptions: { level: 6 },
  });
}

/**
 * Trigger a browser download of the bundle.
 *
 * @param {Blob}   blob
 * @param {string} [filename='surge-deploy.zip']
 */
export function triggerDownload(blob, filename = 'surge-deploy.zip') {
  const url  = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href     = url;
  link.download = filename;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
  // Revoke after a tick so the click handler completes — some browsers
  // race the URL invalidation.
  setTimeout(() => URL.revokeObjectURL(url), 1000);
}
